-- Case 024: tags, column comments, masking assignment, and table alterations
CREATE TAG IF NOT EXISTS GOVERNANCE.DATA_CLASSIFICATION ALLOWED_VALUES 'public', 'internal', 'confidential', 'restricted' COMMENT = 'Allowed data classification values'; CREATE TAG IF NOT EXISTS GOVERNANCE.RETENTION_CLASS ALLOWED_VALUES 'short', 'standard', 'long', 'legal_hold' COMMENT = 'Retention policy class'; ALTER TABLE CORE.PROTECTED_CUSTOMER_PROFILE MODIFY COLUMN email SET MASKING POLICY GOVERNANCE.MASK_EMAIL_CONDITIONAL USING(email,tenant_id),MODIFY COLUMN email SET TAG GOVERNANCE.DATA_CLASSIFICATION = 'restricted',MODIFY COLUMN profile SET TAG GOVERNANCE.DATA_CLASSIFICATION = 'confidential',SET TAG GOVERNANCE.RETENTION_CLASS = 'standard'; ALTER TABLE CORE.PROTECTED_CUSTOMER_PROFILE ADD COLUMN IF NOT EXISTS consent_history ARRAY COMMENT 'Consent snapshots by channel',ADD COLUMN IF NOT EXISTS privacy_context OBJECT COMMENT 'Privacy audit context',ALTER COLUMN updated_at SET DEFAULT CURRENT_TIMESTAMP(); COMMENT ON COLUMN CORE.PROTECTED_CUSTOMER_PROFILE.profile IS 'Raw profile JSON. Contains locale, flags, and activity summary.'; COMMENT ON TABLE CORE.PROTECTED_CUSTOMER_PROFILE IS 'Protected customer profile with governance metadata.';
